import facultyQuestions from "../../data/facultyQuestions";

function FacultyQuestionnaire() {

  return (
    <div
      style={{
        padding: "30px"
      }}
    >
      <h1>
        Faculty Questionnaire
      </h1>

      {
        facultyQuestions.map(
          (section) => (

            <div
              key={
                section.sectionNo
              }
            >
              <h2>
                Section {
                  section.sectionNo
                }
              </h2>

              <p>
                {
                  section.sectionTitle
                }
              </p>
            </div>

          )
        )
      }

    </div>
  );
}

export default FacultyQuestionnaire;
